div.ui-selectonemenu, div.ui-fluid div.ui-selectonemenu, div.ui-selectcheckboxmenu, div.ui-fluid div.ui-selectcheckboxmenu {
    height: 34px;
    display: block;
    overflow: hidden;
    border-color: @select-border-color;
    .border-left-radius(@default-border-radius);
    min-width: 150px; /* primefaces adds min-width: 328px; when on ui-state-exception */

    .ui-selectonemenu-trigger {
        width: @select-trigger-width;
        height: @select-trigger-height;
        padding: 3px 6px;
        .border-left-radius(0px);

        &.ui-state-hover, &.ui-state-focus {
            background: transparent;
            .box-shadow(none);
        }
    }

    .ui-selectonemenu-label {
        padding-left: 6px;
    }
}

atom-text-editor[mini],
  atom-text-editor.mini {
    .text(heading);

    .syntax--text {
      color: @text-color-highlight;
    }

    font-size: 24px;
    line-height: 32px;
    height: auto;
    max-height: none;
    background-color: transparent;
    margin: 0 -@component-padding*2;
    padding: 0 @component-padding*2 @component-padding @component-padding*4;
    border: 0;
    border-radius: 0;
    border-bottom: 1px solid @base-border-color;

    &.is-focused:hover,
    &:hover {
      border-top: 0 !important;
      border-left: 0 !important;
      border-right: 0 !important;
      border-bottom: 1px solid @base-border-color !important;
      background-color: transparent !important;
    }
  }

&__color {
  width: 100%;
  height: 100%;
  box-sizing: border-box;
  display: flex;
  align-items: center;

  .color-inner {
    border: 1px solid @scrollbar-color;
    display: block;
    width: @color-picker-trigger-input-color-inner-size;
    height: @color-picker-trigger-input-color-inner-size;
    color: transparent;
    position: relative;
    border-radius: @border-radius-small;

    &.@{prefix}-size-s {
      width: @color-picker-trigger-input-color-inner-size-s;
      height: @color-picker-trigger-input-color-inner-size-s;
    }

    &.@{prefix}-size-l {
      width: @color-picker-trigger-input-color-inner-size-l;
      height: @color-picker-trigger-input-color-inner-size-l;
    }
  }
}

@media only screen and (min-width: @widescreenMonitorBreakpoint) {
    & when (@variationTableOverflowingShort) {
        .ui.overflowing.table.short {
            max-height: @overflowingWidescreenMaxHeight * 0.75;
        }
    }
    & when (@variationTableOverflowingVeryShort) {
        .ui.overflowing.table[class*="very short"] {
            max-height: @overflowingWidescreenMaxHeight * 0.5;
        }
    }
    .ui.overflowing.table {
        max-height: @overflowingWidescreenMaxHeight;
    }
    & when (@variationTableOverflowingLong) {
        .ui.overflowing.table.long {
            max-height: @overflowingWidescreenMaxHeight * 2;
        }
    }
    & when (@variationTableOverflowingVeryLong) {
        .ui.overflowing.table[class*="very long"] {
            max-height: @overflowingWidescreenMaxHeight * 3;
        }
    }
}

